import '../lib/envelope_codec.dart';
import '../lib/message.dart';
import '../lib/varint.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

bool formatFails(void Function() action) {
  try {
    action();
    return false;
  } on FormatException {
    return true;
  }
}

void main() {
  final firstText = List<String>.filled(140, 'z').join();
  final stream = <int>[
    ...encodeEnvelope(Message('first', firstText)),
    ...encodeEnvelope(const Message('second', 'tail')),
  ];
  final decoded = decodeEnvelopes(stream);
  check(decoded.length == 2, 'concatenated mixed-size envelopes');
  check(decoded[0].text == firstText && decoded[1].id == 'second', 'cursor follows prefix width');
  check(formatFails(() => decodeVarint(<int>[0x80, 0x00])), 'non-canonical prefix rejection');
  check(formatFails(() => decodeVarint(<int>[0x80])), 'truncated prefix rejection');
  print('final tests passed');
}
